={{ (function() {
  try {
    const raw = $('Root Owner Research').first().json.output || '';
    const cleaned = raw.replace(/```json
?/g, '').replace(/```/g, '').trim();
    const match = cleaned.match(/\{[\s\S]*\}/);
    const parsed = JSON.parse(match ? match[0] : cleaned);
    const session = $('Create Heir Session').first().json;

    const INVALID = ['HEIRS OF','HEIR OF','ESTATE OF','UNKNOWN','CHILDREN OF','DESCENDANTS OF'];
    function isValid(name) {
      if (!name || name.trim().length < 3) return false;
      const u = name.toUpperCase();
      if (INVALID.some(p => u.startsWith(p))) return false;
      if (name.trim().split(/\s+/).filter(Boolean).length < 2) return false;
      return true;
    }
    function normKey(n) { return (n || '').toUpperCase().replace(/[^A-Z ]/g, '').trim().replace(/\s+/g, ' '); }

    const seen = new Set();
    const persons = [];
    function add(name, hint) {
      if (!isValid(name)) return;
      const k = normKey(name);
      if (seen.has(k)) return;
      seen.add(k);
      persons.push({ name: name.trim(), relationship_hint: (hint || '').substring(0, 120) });
    }

    // Source 1: SkipGenie relatives
    for (const r of (parsed.relatives || [])) {
      add(r.name || '', r.relationship_hint || '');
    }

    // Source 2: Ancestry obituary family members
    for (const r of (parsed.ancestry_family_members || [])) {
      add(r.name || '', r.relationship_hint || 'child');
    }

    return { session_id: session.session_id, property_id: session.property_id, persons };
  } catch(e) {
    const session = $('Create Heir Session').first().json;
    return { session_id: session.session_id, property_id: session.property_id, persons: [] };
  }
})() }}

