const item = $input.first().json;
const raw = (item.output || '').trim();
if (!raw) return [{ json: item }];
let parsed = {};
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(_) {
  const s = raw.indexOf('{');
  const e = raw.lastIndexOf('}');
