const raw = ($input.first().json.text || $input.first().json.output || '').trim();
const prep = $('Orch - Prep').first().json;

let attempts = [];
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  const parsed = JSON.parse(match ? match[0] : cleaned);
  attempts = (parsed.attempts || []).slice(0, 5);
} catch(e) {}

// Fallback: derive attempts from name if LLM parse failed
if (attempts.length < 5) {
  const name = (prep.name || '').trim();
  const parts = name.split(/\s+/);
  const last  = parts.length > 1 ? parts[parts.length - 1] : parts[0];
  const first = parts.length > 1 ? parts.slice(0, -1).join(' ') : '';
  const init  = first ? first[0] : '';
  attempts = [
    { first_name: first, last_name: last, state: 'NC', city: '' },
    { first_name: init,  last_name: last, state: 'NC', city: '' },
    { first_name: '',    last_name: last, state: 'NC', city: '' },
    { first_name: first, last_name: last, state: '',   city: '' },
    { first_name: last,  last_name: first,state: 'NC', city: '' },
  ].slice(0, 5);
}

return [{ json: {
  attempts,
  name:              prep.name,
  property_id:       prep.property_id,
  session_id:        prep.session_id,
  queue_id:          prep.queue_id,
  loop_context:      prep.loop_context,
  relationship_hint: prep.relationship_hint,
  age:               prep.age   || '',
  phone:             prep.phone || '',
  address:           prep.address || '',
} }];

